class AssetManager:
    def __init__(self):
        self.platforms = {}
        self.formats = {}
        self.default_aspect_ratio = None

    def add_platform(self, platform_name):
        if platform_name in self.platforms:
            return {'status': 'error', 'message': 'Platform already exists.'}
        self.platforms[platform_name] = {}
        return {'status': 'success', 'message': 'Platform added successfully.'}

    def delete_format(self, format_name):
        if format_name not in self.formats:
            return {'status': 'error', 'message': 'Format not found.'}
        del self.formats[format_name]
        return {'status': 'success', 'message': 'Format deleted successfully.'}

    def edit_platform(self, old_name, new_name):
        if old_name not in self.platforms or not new_name:
            return {'status': 'error', 'message': 'Invalid platform name.'}
        self.platforms[new_name] = self.platforms.pop(old_name)
        return {'status': 'success', 'message': 'Platform edited successfully.'}

    def set_default_aspect_ratio(self, aspect_ratio):
        self.default_aspect_ratio = aspect_ratio
        return {'status': 'success', 'message': 'Aspect ratio set successfully.'}

    def define_cropping_logic(self, platform_name, cropping_logic):
        if platform_name not in self.platforms:
            return {'status': 'error', 'message': 'Platform not found.'}
        self.platforms[platform_name]['cropping_logic'] = cropping_logic
        return {'status': 'success', 'message': 'Cropping logic defined successfully.'}

